import stylesText from './cardio-edit-form.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import type { CardioDetails } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);

/** The user-editable subset of cardio_details emitted by the form. */
export interface CardioFormValue {
    distance_m?: number;
    elevation_gain_m?: number;
    avg_hr?: number;
    max_hr?: number;
    gear_name?: string;
}

const template = document.createElement('template');
template.innerHTML = `
    <form class="cardio-form" novalidate>
        <div class="cardio-form__row">
            <label class="cardio-form__field">
                <span>Distance (km)</span>
                <input type="number" id="distance" class="cardio-form__input" min="0" step="0.01" inputmode="decimal" placeholder="optional">
            </label>
            <label class="cardio-form__field">
                <span>Elevation (m)</span>
                <input type="number" id="elevation" class="cardio-form__input" min="0" step="1" inputmode="numeric" placeholder="optional">
            </label>
        </div>

        <div class="cardio-form__row">
            <label class="cardio-form__field">
                <span>Avg HR (bpm)</span>
                <input type="number" id="avg_hr" class="cardio-form__input" min="0" step="1" inputmode="numeric" placeholder="optional">
            </label>
            <label class="cardio-form__field">
                <span>Max HR (bpm)</span>
                <input type="number" id="max_hr" class="cardio-form__input" min="0" step="1" inputmode="numeric" placeholder="optional">
            </label>
        </div>

        <label class="cardio-form__field">
            <span>Gear</span>
            <input type="text" id="gear" class="cardio-form__input" autocomplete="off" placeholder="e.g. road shoes">
        </label>

        <p class="cardio-form__error" id="error" hidden></p>

        <div class="cardio-form__actions">
            <button type="button" class="cardio-form__btn" id="cancel">Cancel</button>
            <button type="submit" class="cardio-form__btn cardio-form__btn--primary" id="submit">Save</button>
        </div>
    </form>
`;

/**
 * Edit form for a cardio activity's metrics (story 145), reached from the
 * Activity Detail Hub's Cardio section. Callback-driven like the other sub-forms.
 * Distance is entered in km and emitted in metres; blank fields emit `undefined`
 * so the caller can null them out. `avg_speed_mps` and `strava_sport_type` are
 * NOT edited here — the hub recomputes pace from distance + duration and carries
 * the sport type through, since the upsert overwrites every column.
 */
export class CardioEditForm extends HTMLElement {
    private _onSubmit: ((value: CardioFormValue) => void) | null = null;
    private _onCancel: (() => void) | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        shadow.querySelector('form')!.addEventListener('submit', (e) => { e.preventDefault(); this.handleSubmit(); });
        shadow.getElementById('cancel')!.addEventListener('click', () => this._onCancel?.());
    }

    /** Prefill from an existing row (distance shown in km). */
    set value(cardio: CardioDetails | null) {
        if (!cardio) return;
        const shadow = this.shadowRoot!;
        if (cardio.distance_m != null) (shadow.getElementById('distance') as HTMLInputElement).value = String(cardio.distance_m / 1000);
        if (cardio.elevation_gain_m != null) (shadow.getElementById('elevation') as HTMLInputElement).value = String(cardio.elevation_gain_m);
        if (cardio.avg_hr != null) (shadow.getElementById('avg_hr') as HTMLInputElement).value = String(cardio.avg_hr);
        if (cardio.max_hr != null) (shadow.getElementById('max_hr') as HTMLInputElement).value = String(cardio.max_hr);
        if (cardio.gear_name) (shadow.getElementById('gear') as HTMLInputElement).value = cardio.gear_name;
    }

    set onSubmit(handler: (value: CardioFormValue) => void) { this._onSubmit = handler; }
    set onCancel(handler: () => void) { this._onCancel = handler; }

    showError(message: string): void {
        const errorEl = this.shadowRoot!.getElementById('error')!;
        errorEl.textContent = message;
        errorEl.hidden = false;
    }

    private num(id: string): number | undefined {
        const raw = (this.shadowRoot!.getElementById(id) as HTMLInputElement).value.trim();
        if (!raw) return undefined;
        const n = Number(raw);
        return Number.isFinite(n) && n >= 0 ? n : undefined;
    }

    private handleSubmit(): void {
        const km = this.num('distance');
        const gear = (this.shadowRoot!.getElementById('gear') as HTMLInputElement).value.trim();
        const value: CardioFormValue = {
            distance_m: km != null ? Math.round(km * 1000) : undefined,
            elevation_gain_m: this.num('elevation'),
            avg_hr: this.num('avg_hr'),
            max_hr: this.num('max_hr'),
            gear_name: gear || undefined,
        };
        this._onSubmit?.(value);
    }
}

if (!customElements.get('cardio-edit-form')) {
    customElements.define('cardio-edit-form', CardioEditForm);
}
