import { HealthService } from '../../services/health.service.js';
import { navigate } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import './activity-edit/activity-edit.component.js';
import type { ActivityEdit, ActivitySourceMode } from './activity-edit/activity-edit.component.js';
import './cardio-edit-form/cardio-edit-form.component.js';
import type { CardioEditForm, CardioFormValue } from './cardio-edit-form/cardio-edit-form.component.js';
import type { Activity, CardioDetails, NewCardioDetails, WorkoutSessionWithDetail } from '@motivation/shared';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../_shared/screen-status.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';
import { documentStyleSheet } from '../../utils/css.js';
import { buildCardioSummaryRows } from './cardio-format.js';
import stylesText from './health-activity-detail.css?inline';

documentStyleSheet(stylesText);

/**
 * Activity Detail Hub at `/health/activity/:id` (story 179). One screen for any
 * activity — a pure run, a lift, a HIT class with both, or a bare manual entry.
 * Stacks three sections: Core (the editable activity form), Cardio (a
 * `cardio_details` summary with inline add/edit/remove on manual rows — story
 * 145; read-only for Strava/calendar), and Workout (session summary with add /
 * edit-exercises / remove). Mirrors the meal-card pattern: the components are
 * visible and navigable from one place. Refetches on mount.
 */
export class HealthActivityEditScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private idValue: string | null = null;
    private contentRoot: HTMLElement | null = null;
    private sectionsRoot: HTMLElement | null = null;
    private activity: Activity | null = null;
    private session: WorkoutSessionWithDetail | null = null;
    private cardio: CardioDetails | null = null;
    private cardioEditing = false;
    private readonly log = createComponentLogger('health-activity-edit-screen');
    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    set entryId(value: string | null) {
        this.idValue = value;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Activity', 'health', '/health');
        this.contentRoot = page.content;

        this.statusNodes.loadingNode.textContent = 'Loading activity…';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.load(); });

        this.sectionsRoot = document.createElement('div');
        this.contentRoot.append(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode, this.sectionsRoot);

        void this.load();
    }

    private async load(): Promise<void> {
        if (!this.idValue || !this.sectionsRoot) return;
        return safeExec(this, this.log, async () => {
            const activity = await HealthService.fetchActivity(this.idValue!);
            if (!activity) throw new Error(`Activity ${this.idValue} not found.`);

            // Calendar activities are synthesized and have no DB subtype rows;
            // skip the extra fetches that would 404/empty for them.
            const [session, cardio] = activity.source === 'calendar'
                ? [null, null]
                : await Promise.all([
                    HealthService.fetchWorkoutSession(activity.id),
                    HealthService.fetchCardioDetails(activity.id),
                ]);

            this.activity = activity;
            this.session = session;
            this.cardio = cardio;
            this.cardioEditing = false;
            this.renderSections();
        });
    }

    private renderSections(): void {
        if (!this.sectionsRoot || !this.activity) return;
        this.clearStatus();

        const mode = resolveSourceMode(this.activity.source);
        this.sectionsRoot.replaceChildren(
            this.buildCoreSection(this.activity, mode),
            this.buildCardioSection(this.activity, this.cardio, mode),
            this.buildWorkoutSection(this.activity, this.session),
        );
    }

    private buildCoreSection(activity: Activity, mode: ActivitySourceMode): HTMLElement {
        const section = sectionEl('Details');
        const editor = document.createElement('activity-edit') as ActivityEdit;
        editor.activity = activity;
        editor.sourceMode = mode;

        editor.onSave = async (id, updates) => {
            return safeExec(this, this.log, async () => {
                await HealthService.updateActivity(id, updates);
                this.returnToDay(activity.date);
            });
        };
        editor.onDelete = async (id) => {
            return safeExec(this, this.log, async () => {
                await HealthService.deleteActivity(id);
                this.returnToDay(activity.date);
            });
        };
        section.appendChild(editor);
        return section;
    }

    private buildCardioSection(activity: Activity, cardio: CardioDetails | null, mode: ActivitySourceMode): HTMLElement {
        const section = sectionEl('Cardio');

        // Inline edit/add form (manual rows only).
        if (this.cardioEditing) {
            const form = document.createElement('cardio-edit-form') as CardioEditForm;
            form.value = cardio;
            form.onCancel = () => { this.cardioEditing = false; this.renderSections(); };
            form.onSubmit = (value) => { void this.handleSaveCardio(activity, value, form); };
            section.appendChild(form);
            return section;
        }

        const rows = cardio ? buildCardioSummaryRows(cardio, activity.type) : [];
        if (rows.length === 0) {
            const empty = document.createElement('p');
            empty.className = 'activity-hub__empty';
            empty.textContent = 'No cardio metrics.';
            section.appendChild(empty);
        } else {
            const dl = document.createElement('dl');
            dl.className = 'activity-hub__rows';
            for (const row of rows) {
                const dt = document.createElement('dt');
                dt.className = 'activity-hub__row-label';
                dt.textContent = row.label;
                const dd = document.createElement('dd');
                dd.className = 'activity-hub__row-value';
                dd.textContent = row.value;
                dl.append(dt, dd);
            }
            section.appendChild(dl);
        }

        // Strava/calendar metrics are the source's truth — read-only here.
        if (mode === 'manual') {
            const actions = document.createElement('div');
            actions.className = 'activity-hub__actions';
            actions.appendChild(this.actionButton(cardio ? 'Edit cardio' : 'Add cardio details', cardio ? 'default' : 'primary', () => {
                this.cardioEditing = true;
                this.renderSections();
            }));
            if (cardio) {
                actions.appendChild(this.actionButton('Remove cardio', 'danger', () => { void this.handleRemoveCardio(activity); }));
            }
            section.appendChild(actions);
        }
        return section;
    }

    private async handleSaveCardio(activity: Activity, value: CardioFormValue, form: CardioEditForm): Promise<void> {
        // The upsert overwrites every column, so send the full desired state:
        // recompute pace from distance + the activity's duration, and carry the
        // imported sport type through.
        const durationS = (activity.duration_minutes ?? 0) * 60;
        const avgSpeed = value.distance_m && durationS > 0 ? value.distance_m / durationS : undefined;
        const payload: Partial<NewCardioDetails> = {
            distance_m: value.distance_m,
            elevation_gain_m: value.elevation_gain_m,
            avg_hr: value.avg_hr,
            max_hr: value.max_hr,
            gear_name: value.gear_name,
            avg_speed_mps: avgSpeed,
            strava_sport_type: this.cardio?.strava_sport_type,
        };
        try {
            await HealthService.upsertCardioDetails(activity.id, payload);
            await this.load();
        } catch (err) {
            this.log.warn('Failed to save cardio details', { err });
            form.showError('Could not save cardio details.');
        }
    }

    private async handleRemoveCardio(activity: Activity): Promise<void> {
        if (!confirm('Remove the cardio metrics from this activity?')) return;
        return safeExec(this, this.log, async () => {
            // An all-empty payload deletes the row server-side.
            await HealthService.upsertCardioDetails(activity.id, {});
            await this.load();
        });
    }

    private buildWorkoutSection(activity: Activity, session: WorkoutSessionWithDetail | null): HTMLElement {
        const section = sectionEl('Workout');
        const actions = document.createElement('div');
        actions.className = 'activity-hub__actions';

        if (session) {
            const exerciseCount = new Set(session.strength_sets.map((s) => s.exercise_id)).size;
            const setCount = session.strength_sets.length;
            const blockCount = session.workout_blocks.length;

            const summary = document.createElement('p');
            summary.className = 'activity-hub__summary';
            summary.textContent = describeSession(exerciseCount, setCount, blockCount);
            section.appendChild(summary);

            actions.appendChild(this.actionButton('Edit exercises', 'primary', () => {
                navigate(`/health/workouts/${encodeURIComponent(activity.id)}`);
            }));

            // The workout_session is the user's own layered detail (Strava only
            // syncs the activity + cardio_details, never the session), so add /
            // remove are offered on every source — including the Strava-imported
            // TRIB3 case where the rounds are logged here.
            actions.appendChild(this.actionButton('Remove workout', 'danger', () => {
                void this.removeWorkout(activity);
            }));
        } else {
            const empty = document.createElement('p');
            empty.className = 'activity-hub__empty';
            empty.textContent = 'No workout logged.';
            section.appendChild(empty);

            actions.appendChild(this.actionButton('Add workout', 'primary', () => {
                void this.addWorkout(activity);
            }));
        }

        if (actions.childElementCount > 0) section.appendChild(actions);
        return section;
    }

    private async addWorkout(activity: Activity): Promise<void> {
        return safeExec(this, this.log, async () => {
            await HealthService.createWorkoutSession({ activity_id: activity.id });
            navigate(`/health/workouts/${encodeURIComponent(activity.id)}`);
        });
    }

    private async removeWorkout(activity: Activity): Promise<void> {
        if (!confirm('Remove the workout from this activity? Logged sets and intervals will be deleted.')) return;
        return safeExec(this, this.log, async () => {
            await HealthService.deleteWorkoutSession(activity.id);
            await this.load();
        });
    }

    private actionButton(label: string, variant: 'primary' | 'danger' | 'default', onClick: () => void): HTMLButtonElement {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'activity-hub__btn';
        if (variant === 'primary') btn.classList.add('activity-hub__btn--primary');
        if (variant === 'danger') btn.classList.add('activity-hub__btn--danger');
        btn.textContent = label;
        btn.addEventListener('click', onClick);
        return btn;
    }

    private returnToDay(date: string): void {
        navigate(`/health/day/${encodeURIComponent(date)}`, { history: 'replace' });
    }
}

function sectionEl(title: string): HTMLElement {
    const section = document.createElement('section');
    section.className = 'activity-hub__section';
    const heading = document.createElement('h3');
    heading.className = 'activity-hub__section-title';
    heading.textContent = title;
    section.appendChild(heading);
    return section;
}

function describeSession(exerciseCount: number, setCount: number, blockCount: number): string {
    const parts: string[] = [];
    if (exerciseCount > 0) parts.push(`${exerciseCount} exercise${exerciseCount === 1 ? '' : 's'}`);
    if (setCount > 0) parts.push(`${setCount} set${setCount === 1 ? '' : 's'}`);
    if (blockCount > 0) parts.push(`${blockCount} interval${blockCount === 1 ? '' : 's'}`);
    return parts.length ? parts.join(' · ') : 'Empty session — add exercises.';
}

function resolveSourceMode(source: Activity['source']): ActivitySourceMode {
    if (source === 'manual') return 'manual';
    if (source === 'calendar') return 'calendar';
    // strava (old API history) + health_connect_* (story 250) are read-only synced rows.
    return 'synced';
}

customElements.define('health-activity-edit-screen', HealthActivityEditScreen);
