import type { CardioDetails } from '@motivation/shared';

/**
 * Read-side formatters for `cardio_details`. Kept framework-free so both the
 * Activity Detail Hub (story 179) and the cardio sub-editor (story 145) can
 * share them. Distances default to km — a km/miles preference is out of scope.
 */

/** Activity types whose pace is more natural as min/km than km/h. */
const PACE_TYPES = new Set(['running', 'walking', 'hiking']);

export function formatDistanceKm(distanceM: number): string {
    return `${(distanceM / 1000).toFixed(2)} km`;
}

export function formatElevation(elevationM: number): string {
    return `${Math.round(elevationM)} m`;
}

/** min/km for foot sports, km/h otherwise. Returns null for non-positive speed. */
export function formatPaceOrSpeed(avgSpeedMps: number, activityType: string): string | null {
    if (!(avgSpeedMps > 0)) return null;
    if (PACE_TYPES.has(activityType)) {
        const secPerKm = 1000 / avgSpeedMps;
        const min = Math.floor(secPerKm / 60);
        const sec = Math.round(secPerKm % 60);
        // Carry a rounded-up 60s into the minutes column (e.g. 5:60 → 6:00).
        const mm = sec === 60 ? min + 1 : min;
        const ss = sec === 60 ? 0 : sec;
        return `${mm}:${String(ss).padStart(2, '0')} /km`;
    }
    return `${(avgSpeedMps * 3.6).toFixed(1)} km/h`;
}

export function formatHeartRate(avgHr?: number, maxHr?: number): string | null {
    if (avgHr && maxHr) return `${avgHr} avg / ${maxHr} max bpm`;
    if (avgHr) return `${avgHr} bpm avg`;
    if (maxHr) return `${maxHr} bpm max`;
    return null;
}

/** "HighIntensityIntervalTraining" → "High Intensity Interval Training". */
export function formatSportType(sportType: string): string {
    return sportType
        .replace(/([a-z])([A-Z])/g, '$1 $2')
        .replace(/_/g, ' ')
        .trim();
}

export interface CardioSummaryRow {
    label: string;
    value: string;
}

/**
 * Build the present-only summary rows for a cardio activity — fields that are
 * absent (e.g. tennis with HR but no distance) produce no row, so the UI never
 * shows empty metrics.
 */
export function buildCardioSummaryRows(cardio: CardioDetails, activityType: string): CardioSummaryRow[] {
    const rows: CardioSummaryRow[] = [];
    if (cardio.distance_m != null && cardio.distance_m > 0) {
        rows.push({ label: 'Distance', value: formatDistanceKm(cardio.distance_m) });
    }
    if (cardio.avg_speed_mps != null) {
        const paceOrSpeed = formatPaceOrSpeed(cardio.avg_speed_mps, activityType);
        if (paceOrSpeed) rows.push({ label: PACE_TYPES.has(activityType) ? 'Pace' : 'Speed', value: paceOrSpeed });
    }
    if (cardio.elevation_gain_m != null && cardio.elevation_gain_m > 0) {
        rows.push({ label: 'Elevation', value: formatElevation(cardio.elevation_gain_m) });
    }
    const hr = formatHeartRate(cardio.avg_hr, cardio.max_hr);
    if (hr) rows.push({ label: 'Heart rate', value: hr });
    if (cardio.gear_name) rows.push({ label: 'Gear', value: cardio.gear_name });
    if (cardio.strava_sport_type) rows.push({ label: 'Sport', value: formatSportType(cardio.strava_sport_type) });
    return rows;
}
